import logo from './../assets/Vector.svg'
import { useEffect, useState } from 'react'
import axios from 'axios'
import Card from '../components/Card'
import './Home.css'

export function Home(){
    const [pokemons, setPokemons] = useState(null)
    const [searchPoke, setSearchPoke] = useState('')


    const api = `https://pokeapi.co/api/v2/pokemon/`

    useEffect(()=>{
        axios.get(api)
            .then((res)=> setPokemons(res.data));
    }, []);


    if(!pokemons){
        return(<p>Não foi possível encontrar pokemons...</p>)
    }


    const pokemonsFound = pokemons.results.filter(poke => 
    poke.name.toLowerCase().includes(searchPoke.toLocaleLowerCase()))



    return (
        <div className='container'>
            <img className='logo' src={logo}></img>
            <input 
                type='text' 
                placeholder='Pesquisar pokemon'
                value={searchPoke}
                onChange={(e)=> setSearchPoke(e.target.value)}
                ></input>
            <h1>Pokedex</h1>

            <div className='Cards'>
                {pokemonsFound.results.map((pokemon, index) => 
                    <Card 
                    key={index}
                    url={pokemon.url}
                    ></Card>
                )}
            </div>

        </div>
    )
}
